import pymongo
from pymongo import MongoClient
import json
from datetime import datetime

class AdvancedMongoFilter:
    def __init__(self, connection_string="mongodb://localhost:27017/", database_name="advanced_filtering"):
        self.client = MongoClient(connection_string)
        self.db = self.client[database_name]
        
    def create_sample_data(self, collection_name="products"):
        collection = self.db[collection_name]
        collection.delete_many({})
        
        sample_data = [
            {"name": "Laptop", "price": 1200, "stock": 15, "category": "Electronics", "specs": {"ram": 16, "storage": 512}},
            {"name": "Mouse", "price": 25, "stock": 100, "category": "Electronics", "specs": {"wireless": True}},
            {"name": "Keyboard", "price": 75, "stock": 50, "category": "Electronics", "specs": {"mechanical": True}},
            {"name": "Monitor", "price": 300, "stock": 30, "category": "Electronics", "specs": {"size": 27, "resolution": "4K"}},
            {"name": "Desk", "price": 250, "stock": 20, "category": "Furniture", "specs": {"material": "wood"}},
            {"name": "Chair", "price": 180, "stock": 35, "category": "Furniture", "specs": {"ergonomic": True}},
            {"name": "Book", "price": 15, "stock": 200, "category": "Books", "specs": {"pages": 350}},
            {"name": "Notebook", "price": 5, "stock": 500, "category": "Stationery", "specs": {"pages": 100}},
        ]
        
        collection.insert_many(sample_data)
        print(f"Inserted {len(sample_data)} sample documents into {collection_name}")
        
    def execute_where_query(self, collection_name, js_expression):
        collection = self.db[collection_name]
        query = {"$where": js_expression}
        results = list(collection.find(query))
        return results
        
    def execute_custom_filter(self, collection_name, filter_dict):
        collection = self.db[collection_name]
        results = list(collection.find(filter_dict))
        return results
        
    def complex_aggregation_with_function(self, collection_name, js_function):
        collection = self.db[collection_name]
        pipeline = [
            {"$match": {"$where": js_function}}
        ]
        results = list(collection.aggregate(pipeline))
        return results
        
    def execute_where_with_params(self, collection_name, js_template, params):
        js_expression = js_template.format(**params)
        return self.execute_where_query(collection_name, js_expression)
        
    def map_reduce_filter(self, collection_name, map_function, reduce_function, query=None):
        collection = self.db[collection_name]
        results = collection.map_reduce(
            map_function,
            reduce_function,
            "results",
            query=query
        )
        return list(self.db.results.find())
        
    def interactive_filter(self):
        print("\n=== Advanced MongoDB Filter Service ===")
        print("Enter collection name (default: 'products'):")
        collection_name = input().strip() or "products"
        
        print("\nSelect filter type:")
        print("1. JavaScript $where expression")
        print("2. Complex JavaScript function")
        print("3. Parameterized JavaScript query")
        print("4. Standard MongoDB query")
        print("5. MapReduce with JavaScript")
        
        choice = input("Enter choice (1-5): ").strip()
        
        if choice == "1":
            print("\nEnter JavaScript expression for $where:")
            print("Example: this.price > 100 && this.stock < 50")
            js_expr = input().strip()
            results = self.execute_where_query(collection_name, js_expr)
            
        elif choice == "2":
            print("\nEnter complex JavaScript function:")
            print("Example: function() { return this.price * this.stock > 5000; }")
            js_func = input().strip()
            results = self.complex_aggregation_with_function(collection_name, js_func)
            
        elif choice == "3":
            print("\nEnter JavaScript template with {param} placeholders:")
            print("Example: this.price > {min_price} && this.category == '{category}'")
            js_template = input().strip()
            print("Enter parameters as JSON (e.g., {\"min_price\": 100, \"category\": \"Electronics\"}):")
            params = json.loads(input().strip())
            results = self.execute_where_with_params(collection_name, js_template, params)
            
        elif choice == "4":
            print("\nEnter MongoDB query as JSON:")
            print("Example: {\"price\": {\"$gt\": 100}, \"category\": \"Electronics\"}")
            query = json.loads(input().strip())
            results = self.execute_custom_filter(collection_name, query)
            
        elif choice == "5":
            print("\nEnter Map function:")
            print("Example: function() { emit(this.category, this.price); }")
            map_func = input().strip()
            print("\nEnter Reduce function:")
            print("Example: function(key, values) { return Array.sum(values); }")
            reduce_func = input().strip()
            results = self.map_reduce_filter(collection_name, map_func, reduce_func)
            
        else:
            print("Invalid choice")
            return
            
        print(f"\n=== Results ({len(results)} documents) ===")
        for idx, doc in enumerate(results, 1):
            doc.pop('_id', None)
            print(f"{idx}. {json.dumps(doc, indent=2)}")
            
    def run_example_queries(self):
        collection_name = "products"
        
        print("\n=== Example 1: Simple $where query ===")
