        print("\n=== Example 3: String manipulation in JavaScript ===")
        js_expr3 = "this.name.length > 5 && this.category.toLowerCase() == 'electronics'"
        results3 = self.execute_where_query(collection_name, js_expr3)
        print(f"Electronics with name length > 5: {len(results3)} items")
        for r in results3:
            print(f"  - {r['name']}")
            
        print("\n=== Example 4: Working with nested objects ===")
        js_expr4 = "this.specs && Object.keys(this.specs).length > 1"
        results4 = self.execute_where_query(collection_name, js_expr4)
        print(f"Products with multiple specs: {len(results4)} items")
        for r in results4:
            print(f"  - {r['name']}: {list(r.get('specs', {}).keys())}")
            
        print("\n=== Example 5: Mathematical operations ===")
        js_expr5 = "Math.sqrt(this.stock) > 5"
